code = """import json

business_file = var_call_HEFZmVXDHVzrLyslw4q48vwv
review_file = var_call_UjaboqC99bHBDsp1YNwyoxYF

with open(business_file, 'r') as f:
    businesses = json.load(f)
with open(review_file, 'r') as f:
    reviews = json.load(f)

# build review mapping
reviews_by_ref = {}
for r in reviews:
    br = r.get('business_ref')
    rating = r.get('rating')
    try:
        rating = float(rating)
    except Exception:
        continue
    reviews_by_ref.setdefault(br, []).append(rating)

markers = [
    'in the categories of', 'in the category of', 'in the fields of',
    'offers a range of services in', 'offers a diverse range of services and products in',
    'offers a range of services, including', 'offers a wide range of services, including',
    'including', 'this establishment offers', 'offers a delightful array of options ranging from'
]
stop_markers = ['making it', 'to meet', 'for all', ' for ']

def extract_categories(desc):
    if not desc or not isinstance(desc, str):
        return []
    s = desc.strip()
    s_lower = s.lower()
    start = None
    for m in markers:
        idx = s_lower.find(m)
        if idx != -1:
            start = idx + len(m)
            break
    if start is None:
        idx = s_lower.find('located at')
        if idx != -1:
            parts = s.split(',')
            if len(parts) > 2:
                candidate = ','.join(parts[2:])
            else:
                candidate = s
        else:
            candidate = s
    else:
        candidate = s[start:]
    # cut at first period
    if '.' in candidate:
        candidate = candidate.split('.', 1)[0]
    tokens = []
    for piece in candidate.split(','):
        subparts = []
        for p in piece.split(' and '):
            for q in p.split('&'):
                subparts.append(q)
        for sp in subparts:
            t = sp.strip().strip("'\" ")
            if not t:
                continue
            low = t.lower()
            cut_at = None
            for sm in stop_markers:
                pos = low.find(sm)
                if pos != -1:
                    cut_at = pos
                    break
            if cut_at is not None:
                t = t[:cut_at].strip()
            if len(t) > 1:
                tokens.append(t)
    # deduplicate preserving order
    seen = set()
    out = []
    for p in tokens:
        if p not in seen:
            seen.add(p)
            out.append(p)
    return out

category_counts = {}
category_ratings = {}
for b in businesses:
    bid = b.get('business_id')
    desc = b.get('description')
    cats = extract_categories(desc)
    if not cats:
        continue
    if not bid or '_' not in bid:
        continue
    num = bid.split('_', 1)[1]
    bref = 'businessref_' + num
    br_ratings = reviews_by_ref.get(bref, [])
    for c in cats:
        category_counts[c] = category_counts.get(c, 0) + 1
        if br_ratings:
            category_ratings.setdefault(c, []).extend(br_ratings)
        else:
            category_ratings.setdefault(c, [])

if not category_counts:
    result = {"category": None, "business_count": 0, "average_rating": None}
else:
    max_count = max(category_counts.values())
    max_cats = [k for k, v in category_counts.items() if v == max_count]
    max_cat = sorted(max_cats)[0]
    ratings = category_ratings.get(max_cat, [])
    if ratings:
        avg = round(sum(ratings) / len(ratings), 2)
    else:
        avg = None
    result = {"category": max_cat, "business_count": max_count, "average_rating": avg}

print("__RESULT__:")
print(json.dumps(result))"""

